// src/pages/LandingPage.js
import React, { useState } from "react";
import { registerUser, loginUser } from "../utils/firebase";
import "./LandingPage.css";

const features = [
  { icon: "🎙️", title: "Record & Transcribe", desc: "Speak naturally — Groq's Whisper model converts your voice to text in seconds." },
  { icon: "📊", title: "Instant Metrics",     desc: "Get your WPM, filler word count, and pause patterns analyzed automatically." },
  { icon: "🤖", title: "AI Coaching",         desc: "Receive personalized feedback powered by Claude to help you speak with confidence." },
  { icon: "📈", title: "Track Progress",      desc: "Every session is saved. Watch your scores trend upward over time." },
];

const scenarios = [
  { label: "Thesis Defense", emoji: "🎓", color: "#7c6cfc" },
  { label: "Job Interview",  emoji: "💼", color: "#fc6c8f" },
  { label: "Recitation",     emoji: "📖", color: "#4ecca3" },
];

function getStrength(pw) {
  if (!pw) return { score: 0, label: "", color: "" };
  let score = 0;
  if (pw.length >= 8)            score++;
  if (/[A-Z]/.test(pw))         score++;
  if (/[0-9]/.test(pw))         score++;
  if (/[^A-Za-z0-9]/.test(pw)) score++;
  const map = [
    { label: "",       color: "" },
    { label: "Weak",   color: "#ef4444" },
    { label: "Fair",   color: "#f59e0b" },
    { label: "Good",   color: "#6366f1" },
    { label: "Strong", color: "#22c55e" },
  ];
  return { score, ...map[score] };
}

const EyeIcon = ({ crossed }) => crossed ? (
  <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
    <path d="M1 8s2.5-5 7-5 7 5 7 5-2.5 5-7 5-7-5-7-5z" stroke="#9ca3af" strokeWidth="1.5"/>
    <circle cx="8" cy="8" r="2" stroke="#9ca3af" strokeWidth="1.5"/>
    <path d="M2 2l12 12" stroke="#9ca3af" strokeWidth="1.5" strokeLinecap="round"/>
  </svg>
) : (
  <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
    <path d="M1 8s2.5-5 7-5 7 5 7 5-2.5 5-7 5-7-5-7-5z" stroke="#9ca3af" strokeWidth="1.5"/>
    <circle cx="8" cy="8" r="2" stroke="#9ca3af" strokeWidth="1.5"/>
  </svg>
);

const LockIcon = () => (
  <svg width="15" height="15" viewBox="0 0 15 15" fill="none">
    <rect x="2.5" y="6.5" width="10" height="7" rx="1.5" stroke="#9ca3af" strokeWidth="1.4"/>
    <path d="M4.5 6.5V4.5a3 3 0 016 0v2" stroke="#9ca3af" strokeWidth="1.4" strokeLinecap="round"/>
  </svg>
);

const MailIcon = () => (
  <svg width="15" height="15" viewBox="0 0 15 15" fill="none">
    <rect x="1" y="3" width="13" height="9" rx="1.5" stroke="#9ca3af" strokeWidth="1.4"/>
    <path d="M1 5l6.5 4.5L14 5" stroke="#9ca3af" strokeWidth="1.4" strokeLinecap="round"/>
  </svg>
);

const UserIcon = () => (
  <svg width="15" height="15" viewBox="0 0 15 15" fill="none">
    <circle cx="7.5" cy="5" r="3" stroke="#9ca3af" strokeWidth="1.4"/>
    <path d="M1.5 13.5c0-3.314 2.686-6 6-6s6 2.686 6 6" stroke="#9ca3af" strokeWidth="1.4" strokeLinecap="round"/>
  </svg>
);

// ── Auth Modal ───────────────────────────────────────────────────────────────
function AuthModal({ initialMode, onClose, onSuccess }) {
  const [mode, setMode]         = useState(initialMode || "login");
  const [name, setName]         = useState("");
  const [email, setEmail]       = useState("");
  const [password, setPassword] = useState("");
  const [confirm, setConfirm]   = useState("");
  const [showPw, setShowPw]     = useState(false);
  const [showCf, setShowCf]     = useState(false);
  const [remember, setRemember] = useState(false);
  const [error, setError]       = useState("");
  const [loading, setLoading]   = useState(false);

  const strength = getStrength(password);

  const switchMode = (m) => {
    setMode(m); setError("");
    setName(""); setEmail(""); setPassword(""); setConfirm("");
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    if (mode === "register") {
      if (!name.trim())         return setError("Please enter your name.");
      if (password.length < 6)  return setError("Password must be at least 6 characters.");
      if (password !== confirm)  return setError("Passwords do not match.");
    }
    setLoading(true);
    try {
      if (mode === "register") await registerUser(name.trim(), email.trim(), password);
      else                      await loginUser(email.trim(), password);
      onSuccess?.();   // ← redirects to dashboard
      onClose();
    } catch (err) {
      const msg = err.code || err.message;
      if (msg.includes("email-already-in-use"))   setError("That email is already registered.");
      else if (msg.includes("user-not-found"))    setError("No account found with that email.");
      else if (msg.includes("wrong-password"))    setError("Incorrect password.");
      else if (msg.includes("invalid-email"))     setError("Please enter a valid email address.");
      else if (msg.includes("too-many-requests")) setError("Too many attempts. Please wait.");
      else setError("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="clario-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className={`clario-modal ${mode}`}>

        {/* ── LEFT PANEL ── */}
        <div className="modal-left">
          <div className="modal-brand">
            <div className="modal-brand-icon">
              <svg width="30" height="30" viewBox="0 0 30 30" fill="none">
                <circle cx="15" cy="15" r="14" stroke="#7c6cfc" strokeWidth="1.8"/>
                <path d="M8 15 Q15 7 22 15" stroke="#7c6cfc" strokeWidth="2" fill="none" strokeLinecap="round"/>
                <circle cx="22" cy="11" r="2.8" fill="#7c6cfc"/>
              </svg>
            </div>
            <div>
              <div className="modal-brand-name">CLARIO</div>
              <div className="modal-brand-sub">AI SPEECH COACH</div>
            </div>
          </div>

          {mode === "register" ? (
            <>
              <h2 className="modal-left-title">Create your account</h2>
              <p className="modal-left-sub">Start your journey to confident communication.</p>
              <div className="modal-steps">
                <div className="modal-step active">
                  <div className="step-num active">1</div>
                  <div className="step-label">Personal Information</div>
                </div>
                <div className="modal-step">
                  <div className="step-num">2</div>
                  <div className="step-label">Security</div>
                </div>
                <div className="modal-step">
                  <div className="step-num">3</div>
                  <div className="step-label">Review</div>
                </div>
              </div>
              {/* Chat bubble illustration */}
              <div className="modal-illus">
                <svg width="140" height="120" viewBox="0 0 140 120" fill="none">
                  <ellipse cx="70" cy="108" rx="55" ry="10" fill="#ede9fe" opacity="0.6"/>
                  <circle cx="70" cy="55" r="42" fill="#f5f3ff"/>
                  <circle cx="70" cy="55" r="30" fill="#ede9fe"/>
                  <rect x="45" y="48" width="5" height="14" rx="2.5" fill="#a78bfa"/>
                  <rect x="54" y="42" width="5" height="26" rx="2.5" fill="#7c6cfc"/>
                  <rect x="63" y="46" width="5" height="18" rx="2.5" fill="#a78bfa"/>
                  <rect x="72" y="38" width="5" height="34" rx="2.5" fill="#7c6cfc"/>
                  <rect x="81" y="44" width="5" height="22" rx="2.5" fill="#a78bfa"/>
                  <rect x="90" y="48" width="5" height="14" rx="2.5" fill="#7c6cfc"/>
                  <rect x="28" y="78" width="44" height="22" rx="11" fill="#c4b5fd"/>
                  <circle cx="40" cy="89" r="3" fill="white"/>
                  <circle cx="50" cy="89" r="3" fill="white"/>
                  <circle cx="60" cy="89" r="3" fill="white"/>
                  <circle cx="108" cy="30" r="4" fill="#c4b5fd" opacity="0.7"/>
                  <circle cx="22"  cy="45" r="3" fill="#ddd6fe" opacity="0.8"/>
                  <circle cx="115" cy="70" r="2" fill="#a78bfa" opacity="0.6"/>
                </svg>
              </div>
            </>
          ) : (
            <>
              <h2 className="modal-left-title">Welcome back! 👋</h2>
              <p className="modal-left-sub">Log in to continue your journey to confident communication.</p>
              {/* Mic illustration */}
              <div className="modal-illus">
                <svg width="150" height="150" viewBox="0 0 150 150" fill="none">
                  <ellipse cx="75" cy="138" rx="45" ry="9" fill="#ede9fe" opacity="0.5"/>
                  <circle cx="75" cy="70" r="62" stroke="#f0edff" strokeWidth="1.5"/>
                  <circle cx="75" cy="70" r="48" stroke="#e0d9ff" strokeWidth="1.5"/>
                  <rect x="57" y="22" width="36" height="62" rx="18" fill="url(#mg2)"/>
                  <line x1="63" y1="38" x2="87" y2="38" stroke="white" strokeWidth="1" opacity="0.3"/>
                  <line x1="63" y1="46" x2="87" y2="46" stroke="white" strokeWidth="1" opacity="0.3"/>
                  <line x1="63" y1="54" x2="87" y2="54" stroke="white" strokeWidth="1" opacity="0.3"/>
                  <path d="M75 84 L75 108" stroke="#7c6cfc" strokeWidth="3.5" strokeLinecap="round"/>
                  <path d="M56 108 Q75 113 94 108" stroke="#7c6cfc" strokeWidth="3.5" strokeLinecap="round"/>
                  <path d="M42 55 Q36 68 42 82" stroke="#a78bfa" strokeWidth="2" fill="none" strokeLinecap="round" opacity="0.8"/>
                  <path d="M33 48 Q24 68 33 88" stroke="#c4b5fd" strokeWidth="1.8" fill="none" strokeLinecap="round" opacity="0.5"/>
                  <path d="M108 55 Q114 68 108 82" stroke="#a78bfa" strokeWidth="2" fill="none" strokeLinecap="round" opacity="0.8"/>
                  <path d="M117 48 Q126 68 117 88" stroke="#c4b5fd" strokeWidth="1.8" fill="none" strokeLinecap="round" opacity="0.5"/>
                  <circle cx="116" cy="28" r="4" fill="#c4b5fd"/>
                  <circle cx="28"  cy="42" r="3" fill="#ddd6fe"/>
                  <circle cx="124" cy="58" r="2" fill="#a78bfa"/>
                  <defs>
                    <linearGradient id="mg2" x1="57" y1="22" x2="93" y2="84" gradientUnits="userSpaceOnUse">
                      <stop offset="0%" stopColor="#b8abf8"/>
                      <stop offset="100%" stopColor="#7c6cfc"/>
                    </linearGradient>
                  </defs>
                </svg>
              </div>
              <p className="modal-copyright">© 2026 CLARIO. All rights reserved.</p>
            </>
          )}
        </div>

        {/* ── RIGHT PANEL ── */}
        <div className="modal-right">
          <button className="modal-close" onClick={onClose} aria-label="Close">
            <svg width="12" height="12" viewBox="0 0 12 12" fill="none">
              <path d="M1 1l10 10M11 1L1 11" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"/>
            </svg>
          </button>

          <h3 className="modal-right-title">
            {mode === "register" ? "Create your account" : "Log in to your account"}
          </h3>
          <p className="modal-right-sub">
            {mode === "register" ? "Fill in your details to get started." : "Enter your credentials to access your dashboard."}
          </p>

          <form className="modal-form" onSubmit={handleSubmit}>

            {/* REGISTER: name + email side by side */}
            {mode === "register" && (
              <div className="form-row">
                <div className="form-field">
                  <label>Full name</label>
                  <div className="field-input-wrap">
                    <span className="field-icon"><UserIcon /></span>
                    <input
                      type="text"
                      placeholder="e.g. Maky Aury Okit"
                      value={name}
                      onChange={e => setName(e.target.value)}
                      required
                    />
                  </div>
                </div>
                <div className="form-field">
                  <label>Email address</label>
                  <div className="field-input-wrap">
                    <span className="field-icon"><MailIcon /></span>
                    <input
                      type="email"
                      placeholder="you@cmu.edu.ph"
                      value={email}
                      onChange={e => setEmail(e.target.value)}
                      required
                    />
                  </div>
                </div>
              </div>
            )}

            {/* LOGIN: email full width */}
            {mode === "login" && (
              <div className="form-field">
                <label>Email address</label>
                <div className="field-input-wrap">
                  <span className="field-icon"><MailIcon /></span>
                  <input
                    type="email"
                    placeholder="s.sanchez.rolchvincent@cmu.edu.ph"
                    value={email}
                    onChange={e => setEmail(e.target.value)}
                    required
                  />
                </div>
              </div>
            )}

            {/* REGISTER: password + confirm side by side */}
            {mode === "register" ? (
              <div className="form-row">
                <div className="form-field">
                  <label>Password</label>
                  <div className="field-input-wrap">
                    <span className="field-icon"><LockIcon /></span>
                    <input
                      type={showPw ? "text" : "password"}
                      placeholder="••••••••••"
                      value={password}
                      onChange={e => setPassword(e.target.value)}
                      required
                    />
                    <button type="button" className="eye-btn" onClick={() => setShowPw(v => !v)}>
                      <EyeIcon crossed={showPw} />
                    </button>
                  </div>
                </div>
                <div className="form-field">
                  <label>Confirm password</label>
                  <div className="field-input-wrap">
                    <span className="field-icon"><LockIcon /></span>
                    <input
                      type={showCf ? "text" : "password"}
                      placeholder="••••••••••"
                      value={confirm}
                      onChange={e => setConfirm(e.target.value)}
                      required
                    />
                    <button type="button" className="eye-btn" onClick={() => setShowCf(v => !v)}>
                      <EyeIcon crossed={showCf} />
                    </button>
                  </div>
                </div>
              </div>
            ) : (
              /* LOGIN: password full width */
              <div className="form-field">
                <label>Password</label>
                <div className="field-input-wrap">
                  <span className="field-icon"><LockIcon /></span>
                  <input
                    type={showPw ? "text" : "password"}
                    placeholder="••••••••••••"
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    required
                  />
                  <button type="button" className="eye-btn" onClick={() => setShowPw(v => !v)}>
                    <EyeIcon crossed={showPw} />
                  </button>
                </div>
              </div>
            )}

            {/* Password strength (register) */}
            {mode === "register" && password && (
              <div className="strength-row">
                <div className="strength-bars">
                  {[1,2,3,4].map(i => (
                    <div
                      key={i}
                      className="strength-seg"
                      style={{ background: i <= strength.score ? strength.color : "#e5e7eb" }}
                    />
                  ))}
                </div>
                <span className="strength-text" style={{ color: strength.color }}>
                  Password strength: <strong>{strength.label}</strong>
                </span>
              </div>
            )}

            {/* Password hint (register) */}
            {mode === "register" && (
              <div className="form-hint">
                <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                  <circle cx="7" cy="7" r="6" stroke="#7c6cfc" strokeWidth="1.2"/>
                  <path d="M7 6v4M7 4.5v.5" stroke="#7c6cfc" strokeWidth="1.2" strokeLinecap="round"/>
                </svg>
                Use at least 8 characters with a mix of letters, numbers, and symbols.
              </div>
            )}

            {/* Remember me + Forgot (login) */}
            {mode === "login" && (
              <div className="login-meta">
                <label className="remember-check">
                  <input type="checkbox" checked={remember} onChange={e => setRemember(e.target.checked)} />
                  <span>Remember me</span>
                </label>
                <button type="button" className="forgot-link">Forgot password?</button>
              </div>
            )}

            {error && <p className="form-error">⚠️ {error}</p>}

            <button className="form-submit" type="submit" disabled={loading}>
              {loading ? (
                <><span className="form-spinner" /> {mode === "register" ? "Creating account..." : "Logging in..."}</>
              ) : (
                <>{mode === "register" ? "Create Account" : "Log In"} <span className="submit-arr">→</span></>
              )}
            </button>
          </form>

          {/* Social (login only) */}
          {mode === "login" && (
            <>
              <div className="social-divider"><span>or continue with</span></div>
              <div className="social-row">
                <button className="social-btn" type="button">
                  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
                    <path d="M17.64 9.2c0-.637-.057-1.251-.164-1.84H9v3.481h4.844c-.209 1.125-.843 2.078-1.796 2.716v2.259h2.908c1.702-1.567 2.684-3.875 2.684-6.615z" fill="#4285F4"/>
                    <path d="M9 18c2.43 0 4.467-.806 5.956-2.184l-2.909-2.259c-.806.54-1.837.86-3.047.86-2.344 0-4.328-1.584-5.036-3.711H.957v2.332A8.997 8.997 0 009 18z" fill="#34A853"/>
                    <path d="M3.964 10.706A5.41 5.41 0 013.682 9c0-.593.102-1.17.282-1.706V4.962H.957A8.996 8.996 0 000 9c0 1.452.348 2.827.957 4.038l3.007-2.332z" fill="#FBBC05"/>
                    <path d="M9 3.58c1.321 0 2.508.454 3.44 1.345l2.582-2.58C13.463.891 11.426 0 9 0A8.997 8.997 0 00.957 4.962L3.964 7.294C4.672 5.163 6.656 3.58 9 3.58z" fill="#EA4335"/>
                  </svg>
                  Google
                </button>
                <button className="social-btn" type="button">
                  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
                    <rect x="0"   y="0"   width="8.5" height="8.5" fill="#F25022"/>
                    <rect x="9.5" y="0"   width="8.5" height="8.5" fill="#7FBA00"/>
                    <rect x="0"   y="9.5" width="8.5" height="8.5" fill="#00A4EF"/>
                    <rect x="9.5" y="9.5" width="8.5" height="8.5" fill="#FFB900"/>
                  </svg>
                  Microsoft
                </button>
              </div>
            </>
          )}

          <p className="modal-switch">
            {mode === "login"
              ? <>Don't have an account? <button onClick={() => switchMode("register")}>Register here</button></>
              : <>Already have an account? <button onClick={() => switchMode("login")}>Log in here</button></>
            }
          </p>
        </div>
      </div>
    </div>
  );
}

// ── Landing Page ─────────────────────────────────────────────────────────────
export default function LandingPage({ navigate, user, onLogout }) {
  const [authModal, setAuthModal] = useState(null);

  const openLogin    = () => setAuthModal("login");
  const openRegister = () => setAuthModal("register");
  const closeModal   = () => setAuthModal(null);

  // After successful auth → go straight to dashboard
  const handleAuthSuccess = () => navigate("dashboard");

  const handleStartPractice = () => {
    if (!user) openLogin();
    else navigate("practice");
  };

  const getInitials = () => {
    const n = user?.displayName || user?.email || "";
    return n.slice(0, 2).toUpperCase();
  };

  return (
    <div className="landing">
      {authModal && (
        <AuthModal
          initialMode={authModal}
          onClose={closeModal}
          onSuccess={handleAuthSuccess}
        />
      )}

      {/* NAV */}
      <nav className="navbar">
        <span className="navbar-logo">CLARIO</span>
        <div className="navbar-links">
          <button className="btn btn-ghost" onClick={() => navigate("dashboard")}>Dashboard</button>
          <button className={user ? "btn btn-primary" : "btn btn-ghost"} onClick={handleStartPractice}>
            {user ? "🎙️ Start Practice" : "Start Practice"}
          </button>
        </div>
        <div className="navbar-auth">
          {user ? (
            <>
              <div className="navbar-user-pill">
                <div className="navbar-avatar">{getInitials()}</div>
                <span className="navbar-name">{user.displayName || user.email}</span>
              </div>
              <button className="btn btn-ghost navbar-logout" onClick={onLogout}>Log out</button>
            </>
          ) : (
            <>
              <div className="navbar-divider" />
              <button className="btn btn-ghost" onClick={openLogin}>Log in</button>
              <button className="btn btn-outline" onClick={openRegister}>Register</button>
            </>
          )}
        </div>
      </nav>

      {/* HERO */}
      <section className="hero">
        <div className="hero-glow" />
        <div className="hero-content">
          <span className="tag tag-purple">AI Speech Coach</span>
          <h1 className="hero-title">
            Speak with<br />
            <span className="hero-gradient">Confidence.</span>
          </h1>
          <p className="hero-sub">
            CLARIO analyzes your speech in real-time — measuring pace, filler words,
            and clarity — then gives you AI-powered coaching to help you improve fast.
          </p>
          <div className="hero-actions">
            <button className="btn btn-primary" onClick={handleStartPractice}>🎙️ Start a Session</button>
            <button className="btn btn-outline" onClick={() => navigate("dashboard")}>View My Progress</button>
          </div>
          <div className="scenario-chips">
            <span className="scenario-label">Practice scenarios:</span>
            {scenarios.map((s) => (
              <span key={s.label} className="scenario-chip" style={{ "--chip-color": s.color }}>
                {s.emoji} {s.label}
              </span>
            ))}
          </div>
        </div>
        <div className="hero-visual">
          <div className="mock-card">
            <div className="mock-top">
              <span className="mock-label">Live Session</span>
              <span className="tag tag-green">● Recording</span>
            </div>
            <div className="mock-waveform">
              {[...Array(20)].map((_, i) => (
                <div key={i} className="mock-bar" style={{ "--delay": `${i * 0.08}s`, "--h": `${20 + Math.sin(i) * 50}%` }} />
              ))}
            </div>
            <div className="mock-metrics">
              <div className="mock-metric"><span className="mock-val">142</span><span className="mock-key">WPM</span></div>
              <div className="mock-metric"><span className="mock-val">3</span><span className="mock-key">Fillers</span></div>
              <div className="mock-metric"><span className="mock-val">87</span><span className="mock-key">Score</span></div>
            </div>
          </div>
        </div>
      </section>

      {/* FEATURES */}
      <section className="features-section">
        <h2 className="section-title">Everything you need to improve</h2>
        <div className="features-grid">
          {features.map((f) => (
            <div key={f.title} className="feature-card card">
              <span className="feature-icon">{f.icon}</span>
              <h3>{f.title}</h3>
              <p>{f.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* CTA */}
      <section className="cta-section">
        <h2>Ready to level up your public speaking?</h2>
        <p>Join thousands of students who practice smarter with CLARIO.</p>
        <button className="btn btn-primary" onClick={handleStartPractice}>
          🎙️ Start Your First Session — It's Free
        </button>
      </section>

      <footer className="footer">
        <span className="navbar-logo">CLARIO</span>
        <span>Built with ❤️ by Rolch, Maky, Cholou, Sofia &amp; the team · CMU Technopreneurship 2026</span>
      </footer>
    </div>
  );
}
